1	/**
2	 * Dashboard Page Content component
3	 * Handles all state management and data fetching for the dashboard page.
4	 *
5	 * Features:
6	 * - Financial metrics overview
7	 * - Responsive layout switching (Mobile vs Desktop)
8	 * - Real-time data refresh
9	 * - Date filtering synchronization
10	 */
11	'use client';
12	
13	import DashboardDesktopLayout from '@/components/CMS/dashboard/DashboardDesktopLayout';
14	import DashboardMobileLayout from '@/components/CMS/dashboard/DashboardMobileLayout';
15	import PageLayout from '@/components/shared/layout/PageLayout';
16	import { NoLicenceeAssigned } from '@/components/shared/ui/NoLicenceeAssigned';
17	import { PieChartLabelRenderer } from '@/components/shared/ui/PieChartLabelRenderer';
18	import { useCurrency } from '@/lib/contexts/CurrencyContext';
19	import {
20	  fetchMetricsData,
21	  fetchTopPerformingDataHelper,
22	  loadGamingLocations,
23	} from '@/lib/helpers/dashboard';
24	import { useDashboardFilters, useDashboardRefresh } from '@/lib/hooks/data';
25	import { useGlobalErrorHandler } from '@/lib/hooks/data/useGlobalErrorHandler';
26	import { useAbortableRequest } from '@/lib/hooks/useAbortableRequest';
27	import { useDashBoardStore } from '@/lib/store/dashboardStore';
28	import { useUserStore } from '@/lib/store/userStore';
29	import { DashboardTotals, TopPerformingData } from '@/lib/types';
30	import { CustomizedLabelProps } from '@/lib/types/components';
31	import { getDefaultChartGranularity } from '@/lib/utils/chart';
32	
33	import { shouldShowNoLicenceeMessage } from '@/lib/utils/licencee';
34	import { TimePeriod, type ChartGranularity } from '@/shared/types/common';
35	import axios from 'axios';
36	import { useCallback, useEffect, useMemo, useRef, useState } from 'react';
37	
38	/**
39	 * Dashboard Page Content Component
40	 */
41	export default function DashboardPageContent() {
42	  // ============================================================================
43	  // State & Hooks
44	  // ============================================================================
45	  const { handleApiCallWithRetry } = useGlobalErrorHandler();
46	  const { displayCurrency } = useCurrency();
47	  const user = useUserStore(state => state.user);
48	
49	  const makeMetricsRequest = useAbortableRequest();
50	  const makeTopPerformingRequest = useAbortableRequest();
51	
52	  const stableHandleApiCallWithRetry = useCallback(handleApiCallWithRetry, [
53	    handleApiCallWithRetry,
54	  ]);
55	
56	  const {
57	    loadingChartData,
58	    setLoadingChartData,
59	    loadingTotals,
60	    setLoadingTotals,
61	    loadingLocations,
62	    setLoadingLocations,
63	    loadingTopPerforming,
64	    setLoadingTopPerforming,
65	    activeFilters,
66	    setActiveFilters,
67	    activeTab,
68	    setActiveTab,
69	    totals,
70	    setTotals,
71	    chartData,
72	    setChartData,
73	    gamingLocations,
74	    setGamingLocations,
75	    selectedLicencee,
76	    setSelectedLicencee,
77	    topPerformingData,
78	    setTopPerformingData,
79	    pieChartSortIsOpen,
80	    setPieChartSortIsOpen,
81	    sortBy,
82	    setSortBy,
83	  } = useDashBoardStore();
84	
85	  const prevTotals = useRef<DashboardTotals | null>(null);
86	  const prevFetchParams = useRef<string>('');
87	  const hasTopPerformingFetchedRef = useRef(false);
88	  const prevTopPerformingKeyRef = useRef<string>('');
89	  const fetchInProgressRef = useRef(false);
90	
91	  const {
92	    activeMetricsFilter,
93	    customDateRange,
94	    setActiveMetricsFilter,
95	    setShowDatePicker,
96	  } = useDashboardFilters({ selectedLicencee });
97	
98	  const [chartGranularity, setChartGranularity] = useState<ChartGranularity>(
99	    () =>
100	      getDefaultChartGranularity(
101	        activeMetricsFilter || 'Today',
102	        customDateRange?.startDate,
103	        customDateRange?.endDate
104	      ) as ChartGranularity
105	  );
106	
107	  const { refreshing, handleRefresh } = useDashboardRefresh({
108	    selectedLicencee,
109	    activeMetricsFilter,
110	    activePieChartFilter: activeMetricsFilter,
111	    customDateRange,
112	    activeTab,
113	    displayCurrency,
114	  });
115	
116	  const [machineStats, setMachineStats] = useState<{
117	    totalMachines: number;
118	    onlineMachines: number;
119	    offlineMachines: number;
120	  } | null>(null);
121	  const [machineStatsLoading, setMachineStatsLoading] = useState(true);
122	
123	  /**
124	   * Fetches machine stats for online/offline counts.
125	   */
126	  useEffect(() => {
127	    let aborted = false;
128	    const fetchMachineStats = async () => {
129	      setMachineStatsLoading(true);
130	      try {
131	        const params = new URLSearchParams();
132	        params.append('licencee', selectedLicencee || 'all');
133	
134	        const res = await axios.get(
135	          `/api/analytics/machines/stats?${params.toString()}`
136	        );
137	        const data = res.data;
138	        if (!aborted) {
139	          setMachineStats({
140	            totalMachines: data.totalMachines || 0,
141	            onlineMachines: data.onlineMachines || 0,
142	            offlineMachines: data.offlineMachines || 0,
143	          });
144	        }
145	      } catch {
146	        if (!aborted) {
147	          setMachineStats({
148	            totalMachines: 0,
149	            onlineMachines: 0,
150	            offlineMachines: 0,
151	          });
152	        }
153	      } finally {
154	        if (!aborted) setMachineStatsLoading(false);
155	      }
156	    };
157	    fetchMachineStats();
158	    return () => {
159	      aborted = true;
160	    };
161	  }, [selectedLicencee]);
162	
163	  // ============================================================================
164	  // Computed
165	  // ============================================================================
166	  const showGranularitySelector = useMemo(() => {
167	    if (
168	      activeMetricsFilter === 'Today' ||
169	      activeMetricsFilter === 'Yesterday'
170	    ) {
171	      return true;
172	    }
173	    if (
174	      activeMetricsFilter === 'Custom' &&
175	      customDateRange?.startDate &&
176	      customDateRange?.endDate
177	    ) {
178	      // Show minute/hourly selector only for same-day custom ranges
179	      const sd =
180	        customDateRange.startDate instanceof Date
181	          ? customDateRange.startDate
182	          : new Date(customDateRange.startDate);
183	      const ed =
184	        customDateRange.endDate instanceof Date
185	          ? customDateRange.endDate
186	          : new Date(customDateRange.endDate);
187	      // Compare calendar dates (same year, month, day)
188	      return (
189	        sd.getFullYear() === ed.getFullYear() &&
190	        sd.getMonth() === ed.getMonth() &&
191	        sd.getDate() === ed.getDate()
192	      );
193	    }
194	    // Show daily/weekly selector for Last 30 Days
195	    if (activeMetricsFilter === '30d' || activeMetricsFilter === 'last30days') {
196	      return true;
197	    }
198	    return false;
199	  }, [activeMetricsFilter, customDateRange]);
200	
201	  const isAdminUser = useMemo(
202	    () =>
203	      Boolean(
204	        user?.roles?.some(role => role === 'admin' || role === 'developer')
205	      ),
206	    [user]
207	  );
208	
209	  const { gameDayOffset } = useDashBoardStore();
210	
211	  const effectiveDateRange = useMemo(() => {
212	    if (customDateRange?.startDate && customDateRange?.endDate) {
213	      return {
214	        startDate: customDateRange.startDate,
215	        endDate: customDateRange.endDate,
216	      };
217	    }
218	
219	    const startDate = new Date();
220	    startDate.setHours(gameDayOffset, 0, 0, 0);
221	
222	    const endDate = new Date(startDate);
223	    endDate.setDate(endDate.getDate() + 1);
224	    endDate.setMinutes(endDate.getMinutes() - 1);
225	
226	    return {
227	      startDate,
228	      endDate,
229	    };
230	  }, [customDateRange, gameDayOffset]);
231	
232	  const dateRangeKey = useMemo(
233	    () =>
234	      `${effectiveDateRange.startDate.getTime()}-${effectiveDateRange.endDate.getTime()}`,
235	    [effectiveDateRange]
236	  );
237	
238	  // ============================================================================
239	  // Effects
240	  // ============================================================================
241	
242	  /**
243	   * Recalculates default chart granularity when date filters change.
244	   */
245	  useEffect(() => {
246	    if (!activeMetricsFilter) return undefined;
247	
248	    const updateGranularity = () => {
249	      const defaultGranularity = getDefaultChartGranularity(
250	        activeMetricsFilter,
251	        customDateRange?.startDate,
252	        customDateRange?.endDate
253	      );
254	      setChartGranularity(defaultGranularity);
255	    };
256	
257	    updateGranularity();
258	
259	    if (activeMetricsFilter === 'Today') {
260	      const interval = setInterval(updateGranularity, 60000);
261	      return () => clearInterval(interval);
262	    }
263	
264	    return undefined;
265	  }, [
266	    activeMetricsFilter,
267	    customDateRange?.startDate,
268	    customDateRange?.endDate,
269	  ]);
270	
271	  const prevGranularityRef = useRef<ChartGranularity | undefined>(undefined);
272	
273	  /**
274	   * Fetches metrics data (totals, chart) and gaming locations.
275	   * It now distinguishes between a general data fetch and a granularity-only change
276	   * to avoid showing a skeleton on the financial cards unnecessarily.
277	   */
278	  useEffect(() => {
279	    if (!activeMetricsFilter) return;
280	
281	    const currentDateRangeKey = dateRangeKey;
282	    const fetchKey = `${activeMetricsFilter}-${selectedLicencee}-${currentDateRangeKey}-${displayCurrency}-${isAdminUser}-${chartGranularity}`;
283	
284	    if (prevFetchParams.current === fetchKey) {
285	      setLoadingChartData(false);
286	      setLoadingTotals(false);
287	      return;
288	    }
289	
290	    const fetchMetrics = async () => {
291	      const isGranularityChangeOnly =
292	        prevGranularityRef.current !== chartGranularity &&
293	        prevFetchParams.current.replace(
294	          `-${prevGranularityRef.current}`,
295	          ''
296	        ) === fetchKey.replace(`-${chartGranularity}`, '');
297	
298	      if (isGranularityChangeOnly) {
299	        setLoadingChartData(true);
300	      } else {
301	        setLoadingTotals(true);
302	        setLoadingChartData(true);
303	        setLoadingLocations(true);
304	      }
305	      fetchInProgressRef.current = true;
306	
307	      try {
308	        // Only fetch locations if it's not a granularity-only change
309	        if (!isGranularityChangeOnly) {
310	          await stableHandleApiCallWithRetry(
311	            () =>
312	              loadGamingLocations(setGamingLocations, selectedLicencee, {
313	                forceAll: isAdminUser || selectedLicencee === 'all',
314	              }),
315	            'Dashboard Locations'
316	          );
317	        }
318	
319	        const metricsResult = await makeMetricsRequest(async signal => {
320	          await fetchMetricsData(
321	            activeMetricsFilter as TimePeriod,
322	            effectiveDateRange,
323	            selectedLicencee,
324	            setTotals,
325	            setChartData,
326	            setActiveFilters,
327	            setShowDatePicker,
328	            displayCurrency,
329	            signal,
330	            // Pass granularity to API for short periods (minute/hourly) and 30d (daily/weekly)
331	            chartGranularity === 'minute' ||
332	              chartGranularity === 'hourly' ||
333	              chartGranularity === 'daily' ||
334	              chartGranularity === 'weekly'
335	              ? chartGranularity
336	              : undefined
337	          );
338	        });
339	
340	        if (metricsResult !== null) {
341	          prevFetchParams.current = fetchKey;
342	        }
343	      } catch (error) {
344	        prevFetchParams.current = '';
345	        console.error('Error fetching dashboard metrics:', error);
346	      } finally {
347	        fetchInProgressRef.current = false;
348	        setLoadingChartData(false);
349	        setLoadingTotals(false);
350	        setLoadingLocations(false);
351	        prevGranularityRef.current = chartGranularity;
352	      }
353	    };
354	
355	    fetchMetrics();
356	  }, [
357	    activeMetricsFilter,
358	    selectedLicencee,
359	    dateRangeKey,
360	    effectiveDateRange,
361	    displayCurrency,
362	    isAdminUser,
363	    stableHandleApiCallWithRetry,
364	    makeMetricsRequest,
365	    chartGranularity,
366	    setGamingLocations,
367	    setTotals,
368	    setChartData,
369	    setActiveFilters,
370	    setShowDatePicker,
371	    setLoadingChartData,
372	    setLoadingTotals,
373	  ]);
374	
375	  /**
376	   * Fetches top performing data.
377	   */
378	  useEffect(() => {
379	    if (!activeMetricsFilter) return;
380	
381	    const effectiveTab = activeTab || 'Cabinets';
382	    const topPerformingKey = `top-performing-${effectiveTab}-${activeMetricsFilter}-${selectedLicencee}-${dateRangeKey}-${displayCurrency}`;
383	
384	    if (prevTopPerformingKeyRef.current === topPerformingKey) return;
385	
386	    const fetchTopPerforming = async () => {
387	      setLoadingTopPerforming(true);
388	      try {
389	        await makeTopPerformingRequest(async signal => {
390	          await fetchTopPerformingDataHelper(
391	            effectiveTab,
392	            activeMetricsFilter as TimePeriod,
393	            (data: TopPerformingData) => {
394	              setTopPerformingData(data);
395	              hasTopPerformingFetchedRef.current = true;
396	              prevTopPerformingKeyRef.current = topPerformingKey;
397	            },
398	            setLoadingTopPerforming,
399	            selectedLicencee,
400	            displayCurrency,
401	            signal,
402	            effectiveDateRange
403	          );
404	        });
405	      } catch (error) {
406	        console.error('Error fetching top performing data:', error);
407	      } finally {
408	        setLoadingTopPerforming(false);
409	      }
410	    };
411	
412	    fetchTopPerforming();
413	  }, [
414	    activeTab,
415	    activeMetricsFilter,
416	    selectedLicencee,
417	    dateRangeKey,
418	    effectiveDateRange,
419	    displayCurrency,
420	    makeTopPerformingRequest,
421	    setTopPerformingData,
422	    setLoadingTopPerforming,
423	  ]);
424	
425	  /**
426	   * Updates previous totals reference when new data arrives.
427	   */
428	  useEffect(() => {
429	    if (
430	      totals &&
431	      (!prevTotals.current ||
432	        totals.moneyIn !== prevTotals.current.moneyIn ||
433	        totals.moneyOut !== prevTotals.current.moneyOut ||
434	        totals.gross !== prevTotals.current.gross)
435	    ) {
436	      prevTotals.current = totals;
437	    }
438	  }, [totals]);
439	
440	  // ============================================================================
441	  // Handlers
442	  // ============================================================================
443	  const renderCustomizedLabel = useCallback(
444	    (props: CustomizedLabelProps) => <PieChartLabelRenderer props={props} />,
445	    []
446	  );
447	
448	  // ============================================================================
449	  // Render
450	  // ============================================================================
451	  if (shouldShowNoLicenceeMessage(user)) {
452	    return <NoLicenceeAssigned />;
453	  }
454	
455	  return (
456	    <PageLayout
457	      headerProps={{
458	        selectedLicencee,
459	        setSelectedLicencee,
460	        disabled: loadingChartData || refreshing,
461	      }}
462	      pageTitle="Dashboard"
463	      hideOptions={false}
464	      hideLicenceeFilter={false}
465	      mainClassName="flex flex-col flex-1 p-4 md:p-6 overflow-x-hidden"
466	      showToaster={true}
467	      onRefresh={handleRefresh}
468	      refreshing={refreshing}
469	    >
470	      {/* Mobile Layout */}
471	      <div className="block md:hidden">
472	        <DashboardMobileLayout
473	          activeFilters={activeFilters}
474	          activeTab={activeTab}
475	          totals={totals}
476	          chartData={chartData || []}
477	          gamingLocations={gamingLocations}
478	          loadingChartData={loadingChartData}
479	          loadingTotals={loadingTotals}
480	          loadingLocations={loadingLocations}
481	          refreshing={refreshing}
482	          pieChartSortIsOpen={pieChartSortIsOpen}
483	          activeMetricsFilter={activeMetricsFilter as TimePeriod}
484	          activePieChartFilter={(activeMetricsFilter || 'Today') as TimePeriod}
485	          topPerformingData={topPerformingData}
486	          setLoadingChartData={setLoadingChartData}
487	          setRefreshing={() => {}}
488	          setActiveFilters={setActiveFilters}
489	          setActiveTab={setActiveTab}
490	          setTotals={setTotals}
491	          setChartData={setChartData}
492	          setPieChartSortIsOpen={setPieChartSortIsOpen}
493	          setTopPerformingData={setTopPerformingData}
494	          setActiveMetricsFilter={setActiveMetricsFilter}
495	          setActivePieChartFilter={setActiveMetricsFilter}
496	          renderCustomizedLabel={renderCustomizedLabel}
497	          selectedLicencee={selectedLicencee}
498	          setSelectedLicencee={setSelectedLicencee}
499	          loadingTopPerforming={loadingTopPerforming}
500	          hasTopPerformingFetched={hasTopPerformingFetchedRef.current}
501	          onRefresh={handleRefresh}
502	          isChangingDateFilter={false}
503	          chartGranularity={chartGranularity}
504	          setChartGranularity={setChartGranularity}
505	          showGranularitySelector={showGranularitySelector}
506	          sortBy={sortBy}
507	          setSortBy={setSortBy}
508	          machineStats={machineStats}
509	          machineStatsLoading={machineStatsLoading}
510	        />
511	      </div>
512	
513	      {/* Desktop Layout */}
514	      <div className="hidden md:block">
515	        <DashboardDesktopLayout
516	          activeFilters={activeFilters}
517	          activeTab={activeTab}
518	          totals={totals}
519	          chartData={chartData || []}
520	          gamingLocations={gamingLocations}
521	          loadingChartData={loadingChartData}
522	          loadingTotals={loadingTotals}
523	          loadingLocations={loadingLocations}
524	          refreshing={refreshing}
525	          pieChartSortIsOpen={pieChartSortIsOpen}
526	          activeMetricsFilter={activeMetricsFilter as TimePeriod}
527	          activePieChartFilter={(activeMetricsFilter || 'Today') as TimePeriod}
528	          topPerformingData={topPerformingData}
529	          setLoadingChartData={setLoadingChartData}
530	          setRefreshing={() => {}}
531	          setActiveFilters={setActiveFilters}
532	          setActiveTab={setActiveTab}
533	          setTotals={setTotals}
534	          setChartData={setChartData}
535	          setPieChartSortIsOpen={setPieChartSortIsOpen}
536	          setTopPerformingData={setTopPerformingData}
537	          setActiveMetricsFilter={setActiveMetricsFilter}
538	          setActivePieChartFilter={setActiveMetricsFilter}
539	          renderCustomizedLabel={renderCustomizedLabel}
540	          selectedLicencee={selectedLicencee}
541	          setSelectedLicencee={setSelectedLicencee}
542	          loadingTopPerforming={loadingTopPerforming}
543	          hasTopPerformingFetched={hasTopPerformingFetchedRef.current}
544	          onRefresh={handleRefresh}
545	          chartGranularity={chartGranularity}
546	          setChartGranularity={setChartGranularity}
547	          showGranularitySelector={showGranularitySelector}
548	          sortBy={sortBy}
549	          setSortBy={setSortBy}
550	          machineStats={machineStats}
551	          machineStatsLoading={machineStatsLoading}
552	        />
553	      </div>
554	    </PageLayout>
555	  );
556	}
