1	/**
2	 * Dashboard Desktop Layout Component
3	 * Dashboard layout optimized for larger screens (xl+).
4	 *
5	 * Features:
6	 * - Date filters with custom date range support
7	 * - Licencee selector for filtering data
8	 * - Refresh button for data reload
9	 * - Financial metrics cards
10	 * - Detailed chart section with metrics filters
11	 * - Map preview of gaming locations
12	 * - Top performing section with tabs (locations vs cabinets)
13	 * - Sorting controls for top performing data
14	 * - Pie chart visualization
15	 * - Skeleton loading states
16	 * - No data messages
17	 *
18	 * @module components/dashboard/DashboardDesktopLayout
19	 */
20	'use client';
21	
22	import DashboardChart from '@/components/CMS/dashboard/DashboardChart';
23	import TopPerformingLocationModal from '@/components/CMS/dashboard/modals/TopPerformingLocationModal';
24	import TopPerformingCabinetModal from '@/components/CMS/dashboard/modals/TopPerformingCabinetModal';
25	import DateFilters from '@/components/shared/ui/common/DateFilters';
26	import FinancialMetricsCards from '@/components/shared/ui/FinancialMetricsCards';
27	import MachineStatusWidget from '@/components/shared/ui/MachineStatusWidget';
28	import MapPreview from '@/components/shared/ui/MapPreview';
29	import { RefreshButtonSkeleton } from '@/components/shared/ui/skeletons/ButtonSkeletons';
30	import {
31	  DashboardChartSkeleton,
32	  DashboardTopPerformingSkeleton,
33	} from '@/components/shared/ui/skeletons/DashboardSkeletons';
34	import type { TopPerformingItem } from '@/lib/types';
35	import type { DashboardDesktopLayoutProps } from '@/lib/types/components';
36	import { ExternalLink, RefreshCw } from 'lucide-react';
37	import { useRouter } from 'next/navigation';
38	import { useState } from 'react';
39	import { Cell, Pie, PieChart, ResponsiveContainer } from 'recharts';
40	
41	export default function DashboardDesktopLayout(
42	  props: DashboardDesktopLayoutProps
43	) {
44	  // ============================================================================
45	  // State & Hooks
46	  // ============================================================================
47	  const router = useRouter();
48	  const [selectedMachine, setSelectedMachine] = useState<{
49	    machineId?: string;
50	    locationId?: string;
51	    machineName?: string;
52	    locationName?: string;
53	    game?: string;
54	    isLocation?: boolean;
55	  } | null>(null);
56	  const [selectedLocation, setSelectedLocation] = useState<{
57	    locationId?: string;
58	    locationName?: string;
59	  } | null>(null);
60	  const [isModalOpen, setIsModalOpen] = useState(false);
61	  const [isLocationModalOpen, setIsLocationModalOpen] = useState(false);
62	
63	  // ============================================================================
64	  // Computed
65	  // ============================================================================
66	  const licenceeName =
67	    props.selectedLicencee && props.selectedLicencee !== 'all'
68	      ? props.selectedLicencee
69	      : 'any licencee';
70	
71	  const NoDataMessage = ({ message }: { message: string }) => (
72	    <div
73	      className="flex flex-col items-center justify-center rounded-lg bg-container p-8 shadow-md"
74	      suppressHydrationWarning
75	    >
76	      <div className="mb-2 text-lg text-gray-500">No Data Available</div>
77	      <div className="text-center text-sm text-gray-400">{message}</div>
78	    </div>
79	  );
80	
81	  // ============================================================================
82	  // Render
83	  // ============================================================================
84	  return (
85	    <div className="grid grid-cols-1 gap-6 xl:grid-cols-5">
86	      {/* ============================================================================
87	         Left Section (Dashboard Content) - 60% Width (3/5 columns)
88	         ============================================================================ */}
89	      <div className="space-y-10 xl:col-span-3">
90	        {/* Date Filter Controls & Machine Status Widget */}
91	        <div className="flex flex-wrap items-center justify-between gap-4">
92	          <div className="flex-shrink-0">
93	            <DateFilters hideAllTime={true} />
94	          </div>
95	          <div className="flex-shrink-0">
96	            <MachineStatusWidget
97	              isLoading={props.machineStatsLoading}
98	              onlineCount={props.machineStats?.onlineMachines ?? 0}
99	              offlineCount={props.machineStats?.offlineMachines ?? 0}
100	              totalCount={props.machineStats?.totalMachines ?? 0}
101	              showTotal
102	            />
103	          </div>
104	        </div>
105	
106	        {/* Metrics Description Text with Refresh Button */}
107	        <div className="flex items-center justify-between gap-2">
108	          {/* Refresh Button with Loading State */}
109	          {props.loadingChartData ? (
110	            <RefreshButtonSkeleton />
111	          ) : (
112	            <div
113	              className={`flex cursor-pointer select-none items-center gap-2 rounded-md bg-buttonActive px-4 py-2 text-white transition-opacity ${
114	                props.loadingChartData || props.refreshing
115	                  ? 'cursor-not-allowed opacity-50'
116	                  : 'hover:bg-buttonActive/90'
117	              }`}
118	              onClick={() => {
119	                if (!(props.loadingChartData || props.refreshing))
120	                  props.onRefresh();
121	              }}
122	              aria-disabled={
