515	                  backgroundColor: selectedMetrics.includes(item.label)
516	                    ? item.color
517	                    : 'transparent',
518	                }}
519	              />
520	              <Label
521	                htmlFor={`metric-${item.label}`}
522	                className="cursor-pointer text-xs font-medium text-gray-700"
523	              >
524	                {item.label}
525	              </Label>
526	            </div>
527	          ))}
528	        </div>
529	      </div>
530	
531	      {/* Scrollable chart container — scrolls horizontally only when chart needs more space */}
532	      <div className="w-full touch-pan-x overflow-x-auto overflow-y-hidden">
533	        <div
534	          className="w-full"
535	          style={minWidth > 0 ? { minWidth: `${minWidth}px` } : undefined}
536	        >
537	          <ResponsiveContainer width="100%" height={320}>
538	            <AreaChart data={gapFilteredChartData}>
539	              <CartesianGrid strokeDasharray="3 3" />
540	              <XAxis
541	                dataKey={
542	                  isHourlyChart
543	                    ? 'time'
544	                    : granularity === 'weekly' || granularity === 'monthly'
545	                      ? 'day'
546	                      : 'day'
547	                }
548	                interval={
549	                  minWidth > 0
550	                    ? isHourlyChart && !isMinuteLevel
551	                      ? 0
552	                      : 'preserveStartEnd'
553	                    : 'preserveStartEnd'
554	                }
555	                minTickGap={isMinuteLevel ? 60 : isHourlyChart ? 30 : 80}
556	                tickFormatter={(val, index) => {
557	                  if (isHourlyChart) {
558	                    const day = gapFilteredChartData[index]?.day;
559	                    if (day && val) {
560	                      // API returns time in UTC format (HH:00 or HH:MM), combine with day to create UTC date
561	                      // Then convert to local time for display
562	                      // Handle both hourly (HH:00) and minute-level (HH:MM) formats
563	                      const timeParts = val.split(':');
564	                      const hours = timeParts[0] || '00';
565	                      const minutes = timeParts[1] || '00';
566	                      const utcDateString = `${day}T${hours}:${minutes}:00Z`;
567	                      const utcDate = new Date(utcDateString);
568	                      // formatTime will convert to local time automatically
569	                      return formatTime(utcDate);
570	                    }
571	                    return val;
572	                  } else {
573	                    // For daily charts (7d, 30d, etc.), format the day value
574	                    // val should be the day string (e.g., "2025-11-16" or "2025-10" for monthly)
575	                    if (val) {
576	                      // Try to get the day from the data point if val is not a valid date string
577	                      const dataPoint = gapFilteredChartData[index];
578	                      const dayValue = dataPoint?.day || val;
579	
580	                      // Check granularity first to determine data format
581	                      // Order matters: monthly comes before weekly since monthly is "YYYY-MM" and weekly is "YYYY-MM-DD"
582	
583	                      // Check if this is monthly data (format: "YYYY-MM")
584	                      if (granularity === 'monthly') {
585	                        // Monthly data comes as "YYYY-MM" format from the API
586	                        const monthlyPattern = /^\d{4}-\d{2}$/;
587	                        if (monthlyPattern.test(dayValue)) {
588	                          // Format as "Oct 2025" for monthly granularity
589	                          const date = new Date(dayValue + '-01'); // Add day to make valid date
590	                          if (!isNaN(date.getTime())) {
591	                            return formatDate(date, {
592	                              month: 'short',
593	                              year: 'numeric',
594	                            });
595	                          }
596	                        }
597	                      }
598	
599	                      // Check if this is weekly data
600	                      // Weekly data comes as the Monday of the week (format: "YYYY-MM-DD")
601	                      // We detect it by checking if granularity is 'weekly'
602	                      if (granularity === 'weekly') {
603	                        const date = new Date(dayValue);
604	                        if (!isNaN(date.getTime())) {
605	                          // Calculate week number within the month (1-5)
606	                          const weekStart = date;
607	                          const monthStart = new Date(
608	                            weekStart.getFullYear(),
609	                            weekStart.getMonth(),
610	                            1
611	                          );
612	                          const daysDiff =
613	                            Math.floor(
614	                              (weekStart.getTime() - monthStart.getTime()) /
615	                                (1000 * 60 * 60 * 24)
616	                            ) + 1;
617	                          const weekNumber = Math.ceil(daysDiff / 7);
618	
619	                          // Format as "Week d of m" (e.g., "Week 1 of Oct")
620	                          return `Week ${weekNumber} of ${formatDate(
621	                            weekStart,
622	                            {
623	                              month: 'short',
624	                            }
625	                          )}`;
626	                        }
627	                      }
628	
629	                      // Validate and format the date for daily charts
630	                      // Parse YYYY-MM-DD as local date (not UTC) to avoid timezone shift
631	                      // e.g., "2026-03-11" should display as "Mar 11" not "Mar 10"
632	                      const dateParts = dayValue.match(
633	                        /^(\d{4})-(\d{2})-(\d{2})$/
634	                      );
635	                      const date = dateParts
636	                        ? new Date(
637	                            Number(dateParts[1]),
638	                            Number(dateParts[2]) - 1,
639	                            Number(dateParts[3])
640	                          )
641	                        : new Date(dayValue);
642	                      if (!isNaN(date.getTime())) {
643	                        return formatDate(date, {
644	                          month: 'short',
645	                          day: 'numeric',
646	                        });
647	                      }
648	                      // If val is already a formatted string, return it
649	                      return String(val);
650	                    }
651	                    return '';
652	                  }
653	                }}
654	              />
655	              <YAxis
656	                domain={yAxisDomain || ['auto', 'auto']}
657	                tickFormatter={value => {
658	                  // Format large numbers compactly for Y-axis to prevent overflow
659	                  const numValue =
660	                    typeof value === 'number'
661	                      ? value
662	                      : parseFloat(String(value)) || 0;
663	                  if (numValue === 0) return '0';
664	                  if (numValue < 1000) return numValue.toFixed(0);
665	                  if (numValue < 1000000)
666	                    return `${(numValue / 1000).toFixed(1)}K`;
667	                  if (numValue < 1000000000)
668	                    return `${(numValue / 1000000).toFixed(1)}M`;
669	                  if (numValue < 1000000000000)
670	                    return `${(numValue / 1000000000).toFixed(1)}B`;
671	                  return `${(numValue / 1000000000000).toFixed(1)}T`;
672	                }}
673	              />
674	              <Tooltip
675	                formatter={(value, name) => {
676	                  // Format value with full number (not abbreviated) in tooltip
677	                  const numValue =
678	                    typeof value === 'number'
679	                      ? value
680	                      : parseFloat(String(value)) || 0;
681	                  const formattedValue = numValue.toLocaleString(undefined, {
682	                    minimumFractionDigits: 2,
683	                    maximumFractionDigits: 2,
684	                  });
685	                  return [formattedValue, name];
686	                }}
687	                labelFormatter={(label, payload) => {
688	                  if (isHourlyChart && payload && payload[0]) {
689	                    const day = payload[0].payload?.day;
690	                    if (day && label) {
691	                      // API returns time in UTC format (HH:00 or HH:MM), combine with day to create UTC date
692	                      // Then convert to local time for display
693	                      // Handle both hourly (HH:00) and minute-level (HH:MM) formats
694	                      const timeParts = String(label).split(':');
695	                      const hours = timeParts[0] || '00';
696	                      const minutes = timeParts[1] || '00';
697	                      const utcDateString = `${day}T${hours}:${minutes}:00Z`;
698	                      const utcDate = new Date(utcDateString);
699	                      // Check if date is valid before formatting
700	                      if (isNaN(utcDate.getTime())) {
701	                        return String(label);
702	                      }
703	                      // formatTime will convert to local time automatically
704	                      return formatTime(utcDate);
705	                    }
706	                  }
707	                  // Validate label before formatting
708	                  if (!label) {
709	                    return '';
710	                  }
711	                  // Try to get day from payload if available (for daily charts)
712	                  if (payload && payload[0] && payload[0].payload?.day) {
713	                    const day = payload[0].payload.day;
714	                    // Parse YYYY-MM-DD as local date to avoid timezone shift
715	                    const dayParts = String(day).match(
716	                      /^(\d{4})-(\d{2})-(\d{2})$/
717	                    );
718	                    const testDate = dayParts
719	                      ? new Date(
720	                          Number(dayParts[1]),
721	                          Number(dayParts[2]) - 1,
722	                          Number(dayParts[3])
723	                        )
724	                      : new Date(day);
725	                    if (!isNaN(testDate.getTime())) {
726	                      return formatDisplayDate(testDate);
727	                    }
728	                  }
729	                  // Try to parse and validate the label as a date
730	                  const labelStr = String(label);
731	                  const labelParts = labelStr.match(
732	                    /^(\d{4})-(\d{2})-(\d{2})$/
733	                  );
734	                  const testDate = labelParts
735	                    ? new Date(
736	                        Number(labelParts[1]),
737	                        Number(labelParts[2]) - 1,
738	                        Number(labelParts[3])
739	                      )
740	                    : new Date(labelStr);
741	                  if (!isNaN(testDate.getTime())) {
742	                    return formatDisplayDate(testDate);
743	                  }
744	                  // Fallback to string representation if label is not a valid date
745	                  return String(label);
746	                }}
747	              />
748	              <defs>
749	                <linearGradient id="colorMoneyIn" x1="0" y1="0" x2="0" y2="1">
750	                  <stop offset="5%" stopColor="#a855f7" stopOpacity={0.8} />
751	                  <stop offset="95%" stopColor="#a855f7" stopOpacity={0} />
752	                </linearGradient>
753	                <linearGradient id="colorMoneyOut" x1="0" y1="0" x2="0" y2="1">
754	                  <stop offset="5%" stopColor="#3b82f6" stopOpacity={0.8} />
755	                  <stop offset="95%" stopColor="#3b82f6" stopOpacity={0} />
756	                </linearGradient>
757	                <linearGradient id="colorGross" x1="0" y1="0" x2="0" y2="1">
758	                  <stop offset="5%" stopColor="#f97316" stopOpacity={0.8} />
759	                  <stop offset="95%" stopColor="#f97316" stopOpacity={0} />
760	                </linearGradient>
761	                <linearGradient id="colorJackpot" x1="0" y1="0" x2="0" y2="1">
762	                  <stop offset="5%" stopColor="#f59e0b" stopOpacity={0.8} />
763	                  <stop offset="95%" stopColor="#f59e0b" stopOpacity={0} />
764	                </linearGradient>
765	              </defs>
766	              {selectedMetrics.includes('Money In') && (
767	                <Area
768	                  type="monotone"
769	                  dataKey="moneyIn"
770	                  stroke="#a855f7"
771	                  strokeWidth={3}
772	                  fill="url(#colorMoneyIn)"
773	                />
774	              )}
775	              {selectedMetrics.includes('Money Out') && (
776	                <Area
777	                  type="monotone"
778	                  dataKey="moneyOut"
779	                  stroke="#3b82f6"
780	                  strokeWidth={3}
781	                  fill="url(#colorMoneyOut)"
782	                />
783	              )}
784	              {selectedMetrics.includes('Jackpot') && (
785	                <Area
786	                  type="monotone"
787	                  dataKey="jackpot"
788	                  stroke="#f59e0b"
789	                  strokeWidth={3}
790	                  fill="url(#colorJackpot)"
791	                />
792	              )}
793	              {selectedMetrics.includes('Gross') && (
794	                <Area
795	                  type="monotone"
796	                  dataKey="gross"
797	                  stroke="#f97316"
798	                  strokeWidth={3}
799	                  fill="url(#colorGross)"
800	                />
