31	import { getDefaultChartGranularity } from '@/lib/utils/chart';
32	import { formatCurrencyWithCode } from '@/lib/utils/currency';
33	import { getGamingDayRangeForPeriod } from '@/lib/utils/gamingDayRange';
34	import { formatMachineDisplayName } from '@/components/shared/ui/machineDisplay';
35	import { TimePeriod } from '@/shared/types/common';
36	import gsap from 'gsap';
37	import { ExternalLink, X } from 'lucide-react';
38	import { useRouter } from 'next/navigation';
39	import { useEffect, useMemo, useRef, useState } from 'react';
40	
41	type TopPerformingCabinetModalProps = {
42	  open: boolean;
43	  machineId: string;
44	  machineName: string;
45	  game?: string;
46	  locationName?: string;
47	  locationId?: string;
48	  onClose: () => void;
49	  onNavigate: () => void;
50	};
51	
52	export default function TopPerformingCabinetModal({
53	  open,
54	  machineId,
55	  machineName,
56	  game,
57	  locationName,
58	  onClose,
59	  onNavigate,
60	}: TopPerformingCabinetModalProps) {
61	  // ============================================================================
62	  // State & Hooks
63	  // ============================================================================
64	  const modalRef = useRef<HTMLDivElement>(null);
65	  const backdropRef = useRef<HTMLDivElement>(null);
66	  const [machineData, setMachineData] = useState<MachineMetricsData | null>(
67	    null
68	  );
69	  const [chartData, setChartData] = useState<dashboardData[]>([]);
70	  const [loading, setLoading] = useState(false);
71	  const [loadingChart, setLoadingChart] = useState(false);
72	  const router = useRouter();
73	  const { displayCurrency } = useCurrency();
74	  const { activePieChartFilter, activeMetricsFilter, customDateRange } =
75	    useDashBoardStore();
76	
77	  // Chart granularity state - initialize after store values are available
78	  const [chartGranularity, setChartGranularity] = useState<
79	    'hourly' | 'minute' | 'daily' | 'weekly' | 'monthly'
80	  >('hourly');
81	
82	  // ============================================================================
83	  // Computed
84	  // ============================================================================
85	  // Use activeMetricsFilter if available (from cabinet detail page), otherwise fall back to activePieChartFilter (from dashboard)
86	  const effectiveTimePeriod =
87	    activeMetricsFilter || activePieChartFilter || 'Today';
88	
89	  // Show granularity selector for Today/Yesterday/Custom (only if Custom spans ≤ 1 gaming day)
90	  // Never show for 7d and 30d - they always use daily format
91	  const showGranularitySelector = useMemo(() => {
92	    const timePeriod = effectiveTimePeriod as TimePeriod;
93	
94	    // Never show granularity selector for 7d and 30d
95	    if (timePeriod === '7d' || timePeriod === '30d') {
96	      return false;
97	    }
98	
99	    if (timePeriod === 'Today' || timePeriod === 'Yesterday') {
100	      return true;
101	    }
102	    if (
103	      timePeriod === 'Custom' &&
104	      customDateRange?.startDate &&
105	      customDateRange?.endDate
106	    ) {
107	      // Check if spans more than 1 gaming day
108	      try {
109	        const range = getGamingDayRangeForPeriod(
110	          'Custom',
111	          8, // Default gaming day start hour
112	          customDateRange.startDate instanceof Date
113	            ? customDateRange.startDate
114	            : new Date(customDateRange.startDate),
115	          customDateRange.endDate instanceof Date
116	            ? customDateRange.endDate
117	            : new Date(customDateRange.endDate)
