45	/**
46	 * Fetches gaming locations from the API and sets them via the provided callback.
47	 * Supports licencee filtering, force-all mode, and request deduplication.
48	 * Falls back to getAllGamingLocations on primary request failure.
49	 * @param {(locations: locations) => void} setGamingLocations - Callback to store fetched locations.
50	 * @param {string} [selectedLicencee] - Optional licencee ID to filter locations.
51	 * @param {{ forceAll?: boolean }} [options] - Optional settings including forceAll flag.
52	 * @returns {Promise<locations[] | undefined>} The fetched locations array or empty array on failure.
53	 */
54	export const loadGamingLocations = async (
55	  setGamingLocations: (locations: locations) => void,
56	  selectedLicencee?: string,
57	  options?: {
58	    forceAll?: boolean;
59	  }
60	) => {
61	  try {
62	    // Lightweight locations fetch (minimal projection, no heavy lookups)
63	    const params = new URLSearchParams();
64	    params.append('minimal', '1');
65	    // Always pass licencee parameter (even if 'all' or empty) so API knows user's selection
66	    if (selectedLicencee) {
67	      params.append('licencee', selectedLicencee);
68	    }
69	    if (options?.forceAll) {
70	      params.append('forceAll', 'true');
71	      params.append('showAll', 'true');
72	    }
73	
74	    const requestKey = `/api/locations?${params.toString()}`;
75	    // Use deduplication to prevent duplicate requests
76	    const responseData = await deduplicateRequest(requestKey, async signal => {
77	      const response = await axios.get(requestKey, { signal });
78	      return response.data;
79	    });
80	
81	    const { locations: locationsData } = responseData;
82	    setGamingLocations(locationsData);
83	
84	    return locationsData;
85	  } catch (error) {
86	    // Silently handle aborted requests - re-throw so useAbortableRequest can handle them
87	    if (isAbortError(error)) {
88	      throw error;
89	    }
90	
91	    const apiError = classifyError(error);
92	    showErrorNotification(apiError, 'Gaming Locations');
93	
94	    if (process.env.NODE_ENV === 'development') {
95	      console.error('Error loading gaming locations:', error);
96	    }
97	
98	    // Fallback to original method
99	    try {
100	      const fallbackLicencee =
101	        options?.forceAll && (!selectedLicencee || selectedLicencee === 'all')
102	          ? undefined
103	          : selectedLicencee;
104	      const locationsData = await getAllGamingLocations(fallbackLicencee);
105	      setGamingLocations(locationsData);
106	      return locationsData;
107	    } catch (fallbackError) {
108	      // Silently handle aborted requests - re-throw so useAbortableRequest can handle them
109	      if (isAbortError(fallbackError)) {
110	        throw fallbackError;
111	      }
112	
113	      const fallbackApiError = classifyError(fallbackError);
114	      showErrorNotification(fallbackApiError, 'Gaming Locations Fallback');
115	    }
116	  }
117	  return [];
118	};
