124	/**
125	 * Fetches dashboard totals using the location aggregation API.
126	 * Ensures consistency between dashboard and locations page totals by summing
127	 * moneyIn, moneyOut, gross, and jackpot across all filtered locations.
128	 * Supports time period filtering, custom date ranges, licencee selection,
129	 * currency conversion, machine type filtering, search, and online status filtering.
130	 * @param {TimePeriod} activeMetricsFilter - The selected time period filter.
131	 * @param {DateRange} customDateRange - Custom date range when time period is 'Custom'.
132	 * @param {string | undefined} selectedLicencee - Optional licencee ID to filter by.
133	 * @param {(totals: DashboardTotals | null) => void} setTotals - State setter for dashboard totals.
134	 * @param {string} [displayCurrency] - Optional currency code for conversion.
135	 * @param {AbortSignal} [signal] - Optional AbortSignal to cancel the request.
136	 * @param {string | null} [machineTypeFilter] - Optional machine type filter.
137	 * @param {() => boolean} [validateFilters] - Optional callback to validate current filters.
138	 * @param {string} [searchTerm] - Optional search term for location filtering.
139	 * @param {string} [selectedStatus] - Optional online status filter.
140	 * @returns {Promise<void>}
141	 */
142	export const fetchDashboardTotals = async (
143	  activeMetricsFilter: TimePeriod,
144	  customDateRange: DateRange,
145	  selectedLicencee: string | undefined,
146	  setTotals: (totals: DashboardTotals | null) => void,
147	  displayCurrency?: string,
148	  signal?: AbortSignal,
149	  machineTypeFilter?: string | null,
150	  validateFilters?: () => boolean,
151	  searchTerm?: string,
152	  selectedStatus?: string
153	) => {
154	  try {
155	    let url = `/api/locationAggregation?timePeriod=${activeMetricsFilter}`;
156	
157	    if (selectedStatus && selectedStatus !== 'All') {
158	      url += `&onlineStatus=${encodeURIComponent(selectedStatus.toLowerCase())}`;
159	    }
160	
161	    if (
162	      activeMetricsFilter === 'Custom' &&
163	      customDateRange.startDate &&
164	      customDateRange.endDate
165	    ) {
166	      // Use full ISO string to include time (important for gameDayOffset)
167	      const fromDate = customDateRange.startDate.toISOString();
168	      const toDate = customDateRange.endDate.toISOString();
169	      url += `&startDate=${encodeURIComponent(fromDate)}&endDate=${encodeURIComponent(toDate)}`;
170	    }
171	
172	    if (selectedLicencee && selectedLicencee !== 'all') {
173	      url += `&licencee=${selectedLicencee}`;
174	    }
175	
176	    if (displayCurrency) {
177	      url += `&currency=${displayCurrency}`;
178	    }
179	
180	    if (machineTypeFilter) {
181	      url += `&machineTypeFilter=${encodeURIComponent(machineTypeFilter)}`;
182	    }
183	
184	    if (searchTerm) {
185	      url += `&search=${encodeURIComponent(searchTerm)}`;
186	    }
187	
188	    // Explicitly request a very high limit to ensure we get ALL filtered locations
189	    // This is critical for accurate totals calculation - we need all locations, not just first page
190	    // Note: limit and page are removed from deduplication key, so this won't prevent deduplication
191	    url += `&limit=1000000&page=1`;
192	
193	    // Note: clearCache parameter removed - deduplication utility now handles this
194	    // The deduplication utility will normalize the request key and prevent duplicate calls
195	
196	    // Use deduplication to prevent duplicate requests
197	    let locationData;
198	    try {
199	      locationData = await deduplicateRequest(url, async abortSignal => {
200	        const response = await axios.get(url, {
201	          signal: abortSignal || signal,
202	        });
203	        return response.data;
204	      });
205	    } catch (error) {
206	      // Check if this is a silent abort marker from deduplicateRequest
207	      if (error instanceof Error && error.message === 'ABORT_SILENT') {
208	        // Silently return - this was an abort error handled by deduplicateRequest
209	        return;
210	      }
211	      // Re-throw other errors so they can be handled by the outer catch block
212	      throw error;
213	    }
214	
215	    // Check if response has error
216	
217	    // Check if response has error
218	    if (locationData.error) {
219	      console.error(
220	        '❌ [fetchDashboardTotals] API returned error:',
221	        locationData.error
222	      );
223	      setTotals(null);
224	      return;
225	    }
226	
227	    // Verify data structure
228	    if (!Array.isArray(locationData.data)) {
229	      console.error(
230	        '❌ [fetchDashboardTotals] API response.data is not an array:',
231	        {
232	          type: typeof locationData.data,
233	          value: locationData.data,
234	          responseKeys: Object.keys(locationData),
235	        }
236	      );
237	      setTotals(null);
238	      return;
239	    }
240	
241	    // Sum up totals from all locations (same logic as locations page)
242	    const totals = locationData.data.reduce(
243	      (
244	        acc: DashboardTotals,
245	        loc: {
246	          moneyIn?: number;
247	          moneyOut?: number;
248	          gross?: number;
249	          jackpot?: number;
250	        }
251	      ) => ({
252	        moneyIn: acc.moneyIn + (loc.moneyIn || 0),
253	        moneyOut: acc.moneyOut + (loc.moneyOut || 0),
254	        gross: acc.gross + (loc.gross || 0),
255	        jackpot: (acc.jackpot || 0) + (loc.jackpot || 0),
256	      }),
257	      { moneyIn: 0, moneyOut: 0, gross: 0, jackpot: 0 }
258	    );
259	
260	    // Validate filters haven't changed before updating totals
261	
262	    // Validate filters haven't changed before updating totals
263	    // This prevents stale data from updating state when filters change rapidly
264	    if (validateFilters && !validateFilters()) {
265	      console.log(
266	        '🔍 [fetchDashboardTotals] Filters changed during request - ignoring stale totals',
267	        {
268	          totals,
269	          machineTypeFilter,
270	        }
271	      );
272	      return;
273	    }
274	
275	    // Convert to DashboardTotals format
276	    setTotals(totals);
277	  } catch (error) {
278	    // CRITICAL: Check for abort errors FIRST - aborting is NOT an error, it's expected when switching filters
279	    // Abort errors should NEVER show error toasts or log errors
280	
281	    // Check axios.isCancel first (most reliable check for axios cancellations)
