283	    if (axios.isCancel && axios.isCancel(error)) {
284	      // Silently return - aborting is expected behavior when switching filters
285	      return;
286	    }
287	
288	    // Check our isAbortError utility (handles other abort error types like AbortError, CanceledError, etc.)
289	    if (isAbortError(error)) {
290	      // Silently return - aborting is expected behavior when switching filters
291	      return;
292	    }
293	
294	    // Check for empty object errors - these might be abort errors that weren't caught above
295	    // Empty objects from axios cancellations sometimes don't serialize properly
296	    // Also check if error has no meaningful properties (empty or only prototype properties)
297	    if (
298	      error &&
299	      typeof error === 'object' &&
300	      (Object.keys(error).length === 0 ||
301	        (Object.keys(error).length === 1 &&
302	          'message' in error &&
303	          !error.message))
304	    ) {
305	      // Empty object or object with only empty message - likely an abort error that wasn't properly detected
306	      // Silently return to avoid false error toasts
307	      return;
308	    }
309	
310	    // Check if this is an axios error that might be an abort in disguise
311	    // Sometimes aborted requests can appear as errors with specific characteristics
312	    const axiosError = error as {
313	      code?: string;
314	      response?: { status?: number; data?: unknown };
315	      message?: string;
316	    };
317	
318	    // If error has code ERR_CANCELED or ECONNABORTED, it's definitely an abort
319	    if (
320	      axiosError.code === 'ERR_CANCELED' ||
321	      axiosError.code === 'ECONNABORTED'
322	    ) {
323	      // Silently return - this is an abort error
324	      return;
325	    }
326	
327	    // Check if this is the ABORT_SILENT marker from deduplicateRequest
328	    if (error instanceof Error && error.message === 'ABORT_SILENT') {
329	      // Silently return - this was an abort error handled by deduplicateRequest
330	      return;
331	    }
332	
333	    // Only show error notification for ACTUAL errors (not aborts)
334	    // Real server errors (500, etc.) should still be shown
335	    const apiError = classifyError(error);
336	    showErrorNotification(apiError, 'Dashboard Totals');
337	
338	    console.error(
339	      '❌ [fetchDashboardTotals] Error fetching dashboard totals:',
340	      {
341	        error,
342	        message: error instanceof Error ? error.message : 'Unknown error',
343	        response: (error as { response?: { data?: unknown; status?: number } })
344	          ?.response?.data,
345	        status: (error as { response?: { status?: number } })?.response?.status,
346	      }
347	    );
348	
349	    setTotals(null);
350	  }
351	};
