373	export const fetchMetricsData = async (
374	  activeMetricsFilter: TimePeriod,
375	  customDateRange: DateRange,
376	  selectedLicencee: string | undefined,
377	  setTotals: (totals: DashboardTotals | null) => void,
378	  setChartData: (data: dashboardData[]) => void,
