384	) => {
385	  // Fetch both totals and chart data in parallel to ensure they complete together
386	  // This prevents the skeleton from disappearing when totals is set but chartData is still loading
387	  await Promise.all([
388	    fetchDashboardTotals(
389	      activeMetricsFilter,
