416	          () => {}, // Don't set totals here, we already did it above
417	          setChartData,
418	          activeMetricsFilter === 'Custom'
419	            ? customDateRange.startDate
420	            : undefined,
421	          activeMetricsFilter === 'Custom'
422	            ? customDateRange.endDate
423	            : undefined,
424	          undefined,
