438	/**
439	 * Fetches top-performing locations or cabinets data based on the active tab and time filter.
440	 * Delegates to fetchTopPerformingData with optional custom date range support.
441	 * Clears data on error to prevent stale/misleading display.
442	 * @param {ActiveTab} activeTab - The active dashboard tab.
443	 * @param {TimePeriod} activePieChartFilter - The selected time period for the pie chart.
444	 * @param {(data: TopPerformingData) => void} setTopPerformingData - State setter for top data.
445	 * @param {(loading: boolean) => void} setLoadingTopPerforming - State setter for loading flag.
446	 * @param {string} [selectedLicencee] - Optional licencee ID to filter by.
447	 * @param {string} [currency] - Optional currency code for conversion.
448	 * @param {AbortSignal} [signal] - Optional AbortSignal to cancel the request.
449	 * @param {DateRange} [customDateRange] - Optional custom date range for 'Custom' period.
450	 * @returns {Promise<void>}
451	 */
452	export const fetchTopPerformingDataHelper = async (
453	  activeTab: ActiveTab,
454	  activePieChartFilter: TimePeriod,
455	  setTopPerformingData: (data: TopPerformingData) => void,
456	  setLoadingTopPerforming: (loading: boolean) => void,
457	  selectedLicencee?: string,
458	  currency?: string,
459	  signal?: AbortSignal,
460	  customDateRange?: DateRange
461	) => {
462	  // Only fetch data if there's a valid filter
463	  if (!activePieChartFilter) {
464	    setTopPerformingData([]);
465	    return;
466	  }
467	
468	  try {
469	    setLoadingTopPerforming(true);
470	    // Clear existing data to prevent stale data display during loading or on error
471	    // This fixes the bug where switching tabs might show previous tab's data if fetch fails
472	    // setTopPerformingData([]); // Optional: enable this if we want to clear immediately, but keeping old data might be better UX if we handle error correctly.
473	    // Actually, for the tab switching bug, user sees stale data.
474	    // If we are switching tabs, we should probably clear or ensure the new data replaces it.
475	
476	    const data = await fetchTopPerformingData(
477	      activeTab,
478	      activePieChartFilter,
479	      selectedLicencee,
480	      currency,
481	      signal,
482	      activePieChartFilter === 'Custom'
483	        ? customDateRange?.startDate || customDateRange?.start
484	        : undefined,
485	      activePieChartFilter === 'Custom'
486	        ? customDateRange?.endDate || customDateRange?.end
487	        : undefined
488	    );
489	    setTopPerformingData(data);
490	  } catch (error) {
491	    // Silently handle aborted requests - this is expected behavior when switching filters
492	    if (isAbortError(error)) {
493	      return;
494	    }
495	
496	    // Only show error notification for actual errors
497	    const apiError = classifyError(error);
498	    showErrorNotification(apiError, 'Top Performing Data');
499	
500	    // On error, clear the data so we don't show stale/misleading info
501	    // This is crucial for fixing the "Cabinets tab showing Location modal" bug
502	    setTopPerformingData([]);
503	
504	    if (process.env.NODE_ENV === 'development') {
505	      console.error('Error fetching top-performing data:', error);
506	    }
507	  } finally {
508	    setLoadingTopPerforming(false);
509	  }
510	};
