516	/**
517	 * Handles the complete dashboard refresh by re-fetching all data in parallel.
518	 * Refreshes metrics totals, chart data, top-performing data, and gaming locations
519	 * simultaneously, managing loading and refreshing state flags.
520	 * @param {TimePeriod} activeMetricsFilter - The selected time period filter.
521	 * @param {DateRange} customDateRange - Custom date range for 'Custom' period.
522	 * @param {string | undefined} selectedLicencee - Optional licencee ID to filter by.
523	 * @param {ActiveTab} activeTab - The active dashboard tab.
524	 * @param {TimePeriod} activePieChartFilter - The selected time period for pie chart.
525	 * @param {(refreshing: boolean) => void} setRefreshing - State setter for refresh flag.
526	 * @param {(loading: boolean) => void} setLoadingChartData - State setter for chart loading flag.
527	 * @param {(loading: boolean) => void} setLoadingTopPerforming - State setter for top data loading flag.
528	 * @param {(totals: DashboardTotals | null) => void} setTotals - State setter for totals.
529	 * @param {(data: dashboardData[]) => void} setChartData - State setter for chart data.
530	 * @param {(filters: ActiveFilters) => void} setActiveFilters - State setter for filters.
531	 * @param {(show: boolean) => void} setShowDatePicker - State setter for date picker visibility.
532	 * @param {(data: TopPerformingData) => void} setTopPerformingData - State setter for top data.
533	 * @param {string} [displayCurrency] - Optional currency code for conversion.
534	 * @returns {Promise<void>}
535	 */
536	export const handleDashboardRefresh = async (
537	  activeMetricsFilter: TimePeriod,
538	  customDateRange: DateRange,
539	  selectedLicencee: string | undefined,
540	  activeTab: ActiveTab,
541	  activePieChartFilter: TimePeriod,
542	  setRefreshing: (refreshing: boolean) => void,
543	  setLoadingChartData: (loading: boolean) => void,
544	  setLoadingTopPerforming: (loading: boolean) => void,
545	  setTotals: (totals: DashboardTotals | null) => void,
546	  setChartData: (data: dashboardData[]) => void,
547	  setActiveFilters: (filters: ActiveFilters) => void,
548	  setShowDatePicker: (show: boolean) => void,
549	  setTopPerformingData: (data: TopPerformingData) => void,
550	  displayCurrency?: string
551	) => {
552	  setRefreshing(true);
553	  setLoadingChartData(true);
554	  setLoadingTopPerforming(true);
555	
556	  try {
557	    // In refresh: also refetch gaming locations to ensure map data stays in sync
558	    const locationsParams = new URLSearchParams();
559	    locationsParams.append('minimal', '1');
560	    if (selectedLicencee && selectedLicencee !== 'all') {
561	      locationsParams.append('licencee', selectedLicencee);
562	    }
563	
564	    // Parallelize metrics + top-performing + a lightweight locations ping to warm caches
565	    const [, topPerformingDataResult] = await Promise.all([
566	      fetchMetricsData(
567	        activeMetricsFilter,
568	        customDateRange,
569	        selectedLicencee,
570	        setTotals,
571	        setChartData,
572	        setActiveFilters,
573	        setShowDatePicker,
574	        displayCurrency
575	      ),
576	      fetchTopPerformingData(
577	        activeTab,
578	        activePieChartFilter,
579	        selectedLicencee,
580	        displayCurrency,
581	        undefined,
582	        activePieChartFilter === 'Custom'
583	          ? customDateRange?.startDate
584	          : undefined,
585	        activePieChartFilter === 'Custom' ? customDateRange?.endDate : undefined
586	      ),
587	      axios.get(`/api/locations?${locationsParams.toString()}`),
588	    ]);
589	    setTopPerformingData(topPerformingDataResult);
590	  } catch (error) {
591	    // Silently handle aborted requests - this is expected behavior when switching filters
592	    if (isAbortError(error)) {
593	      return;
594	    }
595	
596	    const apiError = classifyError(error);
597	    showErrorNotification(apiError, 'Dashboard Refresh');
598	
599	    if (process.env.NODE_ENV === 'development') {
600	      console.error('Error refreshing data:', error);
601	    }
602	  } finally {
603	    setRefreshing(false);
604	    setLoadingChartData(false);
605	    setLoadingTopPerforming(false);
606	  }
607	};
