312	          chartUrl += `&currency=${displayCurrency}`;
313	        }
314	
315	        if (granularity) {
316	          chartUrl += `&granularity=${granularity}`;
317	        }
318	
319	        const chartResponse = await axios.get<{
320	          trends: Array<{
321	            day: string;
322	            time?: string;
323	            [key: string]:
324	              | {
325	                  drop: number;
326	                  gross: number;
327	                  totalCancelledCredits?: number;
328	                }
329	              | string
330	              | undefined;
331	          }>;
332	          isHourly: boolean;
333	        }>(chartUrl, {
334	          headers: {
335	            'Cache-Control': 'no-cache',
336	          },
337	        });
338	
339	        const { trends, isHourly } = chartResponse.data;
340	
341	        // Check if API response contains minute-level data
342	        const hasMinuteLevelData = trends.some(trend => {
343	          if (!trend.time) return false;
344	          const timeParts = trend.time.split(':');
345	          if (timeParts.length !== 2) return false;
346	          const minutes = parseInt(timeParts[1], 10);
347	          return !isNaN(minutes) && minutes !== 0;
348	        });
349	
350	        // Determine if we should use minute or hourly based on API response and granularity
351	        let useMinute = false;
352	        let useHourly = false;
353	
354	        if (granularity) {
355	          if (granularity === 'minute') {
356	            useMinute = true;
357	            useHourly = false;
358	          } else if (granularity === 'hourly') {
359	            useMinute = false;
360	            useHourly = true;
361	          }
362	        } else {
363	          // Auto-detect based on API response
364	          useMinute = hasMinuteLevelData;
365	          useHourly = isHourly && !hasMinuteLevelData;
366	        }
367	
368	        // Transform trends to dashboardData format (same as location details page)
369	        const filteredChart: dashboardData[] = trends.map(trend => {
370	          // Find location data - try exact match first, then try string comparison
371	          // This handles ObjectId vs string differences
372	          let locationData:
373	            | {
374	                drop: number;
375	                gross: number;
376	                totalCancelledCredits?: number;
377	              }
378	            | undefined;
379	
380	          // First try direct access
381	          if (trend[locationId]) {
382	            locationData = trend[locationId] as {
383	              drop: number;
384	              gross: number;
385	              totalCancelledCredits?: number;
386	            };
387	          } else {
388	            // Try to find by string comparison (handles ObjectId vs string differences)
389	            const locationKey = Object.keys(trend).find(
390	              key =>
391	                key !== 'day' &&
392	                key !== 'time' &&
393	                String(key) === String(locationId)
394	            );
395	            if (locationKey) {
396	              locationData = trend[locationKey] as {
397	                drop: number;
398	                gross: number;
399	                totalCancelledCredits?: number;
400	              };
401	            }
402	          }
403	
404	          if (!locationData) {
405	            // Return empty data point if location not found in trend
406	            return {
407	              xValue: useHourly || useMinute ? trend.time || '' : trend.day,
408	              day: trend.day,
409	              time: trend.time || '',
410	              moneyIn: 0,
411	              moneyOut: 0,
412	              gross: 0,
413	              location: locationId,
414	            };
415	          }
416	
417	          const day = trend.day;
418	          let time = '';
419	
420	          if (trend.time) {
421	            if (useHourly) {
422	              const [hh] = trend.time.split(':');
423	              time = `${hh.padStart(2, '0')}:00`;
424	            } else if (useMinute) {
425	              time = trend.time;
426	            } else {
427	              time = trend.time || '';
428	            }
429	          }
430	
431	          const xValue = useHourly || useMinute ? time : day;
432	
433	          return {
434	            xValue,
435	            day,
436	            time,
437	            moneyIn: locationData.drop || 0,
438	            moneyOut: locationData.totalCancelledCredits || 0,
439	            gross: locationData.gross || 0,
440	            location: locationId,
441	          };
442	        });
443	
444	        // Use location totals from reports API if available, otherwise calculate from chart data
445	        const moneyIn =
446	          locationTotals?.moneyIn ??
447	          filteredChart.reduce((sum, item) => sum + (item.moneyIn || 0), 0);
448	        const moneyOut =
449	          locationTotals?.moneyOut ??
450	          filteredChart.reduce((sum, item) => sum + (item.moneyOut || 0), 0);
451	        const gross =
452	          locationTotals?.gross ??
453	          filteredChart.reduce((sum, item) => sum + (item.gross || 0), 0);
454	
455	        // Get location info from first cabinet if available, or use basic info
456	        const cabinets = Array.isArray(locationResponseData)
457	          ? locationResponseData
458	          : [];
459	        const totalMachines = locationTotals?.totalMachines ?? cabinets.length;
460	        const onlineMachines =
461	          locationTotals?.onlineMachines ??
462	          cabinets.filter((cab: { online?: boolean }) => cab.online).length;
463	
464	        setLocationData({
465	          _id: locationInfo?._id || locationInfo?.locationId || locationId,
466	          name:
467	            locationInfo?.locationName || locationInfo?.name || locationName,
468	          address: locationInfo?.address,
469	          moneyIn,
470	          moneyOut,
471	          gross,
472	          totalMachines,
473	          onlineMachines,
474	        });
475	
476	        // Use filtered data
477	        setChartData(filteredChart);
478	      } catch (error) {
479	        console.error('Error fetching location data:', error);
480	      } finally {
481	        setLoading(false);
482	        setLoadingChart(false);
483	      }
484	    };
485	
486	    fetchData();
487	  }, [
488	    open,
