1	/**
2	 * Dashboard Filters Custom Hook
3	 *
4	 * Provides a custom hook for managing dashboard filter state and logic.
5	 * It handles filter initialization, validation, state management, and
6	 * provides memoized setters to prevent unnecessary re-renders.
7	 *
8	 * Features:
9	 * - Manages active metrics filter state
10	 * - Manages pie chart filter state
11	 * - Handles custom date range selection
12	 * - Validates filter configurations
13	 * - Provides reset functionality
14	 * - Memoized setters for performance
15	 */
16	
17	import { useDashBoardStore } from '@/lib/store/dashboardStore';
18	import { setTimeToGamingDayStart } from '@/shared/utils/dateFormat';
19	import type { TimePeriod, dateRange } from '@/lib/types';
20	import type {
21	  UseDashboardFiltersProps,
22	  UseDashboardFiltersReturn,
23	} from '@/lib/types/dashboard';
24	import { useCallback, useEffect, useMemo } from 'react';
25	
26	export function useDashboardFilters({
27	  selectedLicencee,
28	}: UseDashboardFiltersProps): UseDashboardFiltersReturn {
29	  // ============================================================================
30	  // State & Hooks
31	  // ============================================================================
32	  const {
33	    activeMetricsFilter,
34	    setActiveMetricsFilter,
35	    activePieChartFilter,
36	    setActivePieChartFilter,
37	    customDateRange,
38	    setCustomDateRange,
39	    showDatePicker,
40	    setShowDatePicker,
41	  } = useDashBoardStore();
42	
43	  // Ensure showDatePicker is boolean
44	  const isShowDatePicker = Boolean(showDatePicker);
45	
46	  // ============================================================================
47	  // Effects
48	  // ============================================================================
49	
50	  // Initialize selected licencee on component mount
51	  useEffect(() => {
52	    if (!selectedLicencee) {
53	      // This would be handled by the parent component
54	    }
55	  }, [selectedLicencee]);
56	
57	  // ============================================================================
58	  // Computed
59	  // ============================================================================
60	
61	  // Validate if current filter configuration is valid
62	  const isFilterValid = useMemo(() => {
63	    if (!activeMetricsFilter) return false;
64	
65	    if (activeMetricsFilter === 'Custom') {
66	      return Boolean(customDateRange?.startDate && customDateRange?.endDate);
67	    }
68	
69	    return true;
70	  }, [activeMetricsFilter, customDateRange]);
71	
72	  // ============================================================================
73	  // Handlers
74	  // ============================================================================
75	
76	  // Reset all filters to default state
77	  const resetFilters = useCallback(() => {
78	    const { gameDayOffset } = useDashBoardStore.getState();
79	    const today = new Date();
80	    const startDate = setTimeToGamingDayStart(today, gameDayOffset);
81	
82	    const tomorrow = new Date(today);
83	    tomorrow.setDate(tomorrow.getDate() + 1);
84	    const endDate = setTimeToGamingDayStart(tomorrow, gameDayOffset);
85	
86	    setActiveMetricsFilter('Today');
87	    setActivePieChartFilter('Today');
88	    setCustomDateRange({
89	      startDate,
90	      endDate,
91	    });
92	    setShowDatePicker(false);
93	  }, [
94	    setActiveMetricsFilter,
95	    setActivePieChartFilter,
96	    setCustomDateRange,
97	    setShowDatePicker,
98	  ]);
99	
100	  // Memoize setters to prevent unnecessary re-renders
101	  const memoizedSetActiveMetricsFilter = useCallback(
102	    (filter: TimePeriod | '') => {
103	      setActiveMetricsFilter(filter);
104	    },
105	    [setActiveMetricsFilter]
106	  );
107	
108	  const memoizedSetActivePieChartFilter = useCallback(
109	    (filter: TimePeriod | '') => {
110	      setActivePieChartFilter(filter);
111	    },
112	    [setActivePieChartFilter]
113	  );
114	
115	  const memoizedSetCustomDateRange = useCallback(
116	    (range: dateRange) => {
117	      setCustomDateRange(range);
118	    },
119	    [setCustomDateRange]
120	  );
121	
122	  const memoizedSetShowDatePicker = useCallback(
123	    (show: boolean) => {
124	      setShowDatePicker(show);
125	    },
126	    [setShowDatePicker]
127	  );
128	
129	  return {
130	    activeMetricsFilter,
131	    activePieChartFilter,
132	    customDateRange,
133	    showDatePicker: isShowDatePicker,
134	    setActiveMetricsFilter: memoizedSetActiveMetricsFilter,
135	    setActivePieChartFilter: memoizedSetActivePieChartFilter,
136	    setCustomDateRange: memoizedSetCustomDateRange,
137	    setShowDatePicker: memoizedSetShowDatePicker,
138	    isFilterValid,
139	    resetFilters,
140	  };
141	}
