1	/**
2	 * Machine Statistics API Route
3	 *
4	 * This route handles fetching machine statistics with role-based access control.
5	 * It supports:
6	 * - Filtering by licencee
7	 * - Role-based location filtering
8	 * - Machine counts (total, online, SAS)
9	 * - Financial metrics (drop, cancelled credits, gross)
10	 *
11	 * @module app/api/analytics/machines/stats/route
12	 */
13	
14	import { getMachineStatsForAnalytics } from '@/app/api/lib/helpers/reports/analytics';
15	import {
16	  getUserAccessibleLicenceesFromToken,
17	  getUserLocationFilter,
18	} from '@/app/api/lib/helpers/licenceeFilter';
19	import { getUserFromServer } from '@/app/api/lib/helpers/users/users';
20	import { connectDB } from '@/app/api/lib/middleware/db';
21	import { NextRequest, NextResponse } from 'next/server';
22	import {
23	  logRouteFetch,
24	  logRouteError,
25	  extractUserFromRequest,
26	} from '@/app/api/lib/utils/routeLogger';
27	
28	/**
29	 * GET /api/analytics/machines/stats
30	 *
31	 * Returns aggregate machine statistics (total, online, SAS counts and financial totals) scoped to the user's accessible locations. Used by the Analytics machines stats panel.
32	 *
33	 * Query params:
34	 * @param licencee {string} Optional. Scopes results to this licencee. Pass 'all' or omit to include all accessible licencees.
35	 *
36	 * Flow:
37	 * 1. Parse and validate request parameters
38	 * 2. Connect to database
39	 * 3. Authenticate user and get accessible locations
40	 * 4. Validate location access
41	 * 5. Fetch machine statistics
42	 * 6. Return machine statistics
43	 */
44	export async function GET(request: NextRequest) {
45	  const startTime = Date.now();
46	  const functionName = 'GET /api/analytics/machines/stats';
47	  const user = extractUserFromRequest(request);
48	
49	  try {
50	    // ============================================================================
51	    // STEP 1: Parse and validate request parameters
52	    // ============================================================================
53	    const { searchParams } = new URL(request.url);
54	    const licencee = searchParams.get('licencee');
55	    const effectiveLicencee =
56	      licencee && licencee.toLowerCase() !== 'all' ? licencee : null;
57	
58	    // ============================================================================
59	    // STEP 2: Connect to database
60	    // ============================================================================
61	    await connectDB();
62	
63	    // ============================================================================
64	    // STEP 3: Authenticate user and get accessible locations
65	    // ============================================================================
66	    const userAccessibleLicencees = await getUserAccessibleLicenceesFromToken();
67	    const userPayload = await getUserFromServer();
68	    const userRoles = (userPayload?.roles as string[]) || [];
69	    let userLocationPermissions: string[] = [];
70	    if (
71	      Array.isArray(
72	        (userPayload as { assignedLocations?: string[] })?.assignedLocations
73	      )
74	    ) {
75	      userLocationPermissions = (userPayload as { assignedLocations: string[] })
76	        .assignedLocations;
77	    }
78	
79	    const allowedLocationIds = await getUserLocationFilter(
80	      userAccessibleLicencees,
81	      effectiveLicencee ?? undefined,
82	      userLocationPermissions,
83	      userRoles
84	    );
85	
86	    // ============================================================================
87	    // STEP 4: Validate location access
88	    // ============================================================================
89	    if (allowedLocationIds !== 'all') {
90	      if (
91	        !Array.isArray(allowedLocationIds) ||
92	        allowedLocationIds.length === 0
93	      ) {
94	        const zeroStats = {
95	          totalDrop: 0,
96	          totalCancelledCredits: 0,
97	          totalGross: 0,
98	          totalMachines: 0,
99	          onlineMachines: 0,
100	          sasMachines: 0,
101	        };
102	        return NextResponse.json({
103	          stats: zeroStats,
104	          totalMachines: 0,
105	          onlineMachines: 0,
106	          offlineMachines: 0,
107	        });
108	      }
109	    }
110	
111	    // ============================================================================
112	    // STEP 5: Fetch machine statistics
113	    // ============================================================================
114	    const result = await getMachineStatsForAnalytics(allowedLocationIds);
115	
116	    // ============================================================================
117	    // STEP 6: Return machine statistics
118	    // ============================================================================
119	    const duration = Date.now() - startTime;
120	    logRouteFetch(
121	      functionName,
122	      'GET',
123	      '/api/analytics/machines/stats',
124	      1,
125	      user,
126	      duration
127	    );
128	
129	    if (duration > 1000) {
130	      console.warn(
131	        `[Analytics Machines Stats GET API] Completed in ${duration}ms`
132	      );
133	    }
134	    return NextResponse.json(result);
135	  } catch (error) {
136	    const duration = Date.now() - startTime;
137	    const errorMessage =
138	      error instanceof Error ? error.message : 'Failed to fetch machine stats';
139	    logRouteError(
140	      functionName,
141	      'GET',
142	      '/api/analytics/machines/stats',
143	      errorMessage,
144	      user
145	    );
146	    console.error(
147	      `[Machine Stats GET API] Error after ${duration}ms:`,
148	      errorMessage
149	    );
150	    return NextResponse.json(
151	      {
152	        message: 'Failed to fetch machine stats',
153	        error: errorMessage,
154	      },
155	      { status: 500 }
156	    );
157	  }
158	}
