1	/**
2	 * Location Aggregation API Route
3	 *
4	 * This route handles fetching aggregated location metrics with filtering and currency conversion.
5	 * It supports:
6	 * - GET: Retrieves location metrics with optional filtering by time period, licencee, machine type,
7	 *        and currency conversion for admin/developer users viewing all licencees
8	 *
9	 * @module app/api/locationAggregation/route
10	 */
11	
12	import {
13	  clearCache,
14	  getCacheKey,
15	  getCachedData,
16	  setCachedData,
17	} from '@/app/api/lib/helpers/cacheUtils';
18	import { convertLocationCurrency } from '@/app/api/lib/helpers/currency/location';
