46	/**
47	 * Main GET handler for location aggregation
48	 *
49	 * @param {string} timePeriod - Time range preset ('Today', 'Yesterday', '7d', etc.)
50	 * @param {string} licencee - Filter aggregation by licencee name
51	 * @param {string} currency - Target currency code for financial values
52	 * @param {string} machineTypeFilter - Filter by capabilities ('LocalServersOnly', etc.)
53	 * @param {boolean} clearCache - Force cache invalidation
54	 * @param {boolean} sasEvaluationOnly - Only include machines with SAS data
55	 * @param {boolean} basicList - Return simplified location structure
56	 * @param {string} selectedLocations - Comma-separated list of IDs to include
57	 * @param {number} page - Page number for pagination
58	 * @param {number} limit - Items per page
59	 * @param {string} search - Search query for location name
60	 * @param {string} onlineStatus - Filter by location connectivity
61	 * @param {string} startDate - ISO date for custom range start
62	 * @param {string} endDate - ISO date for custom range end
63	 * @param {string} testUserId - Specific user ID to simulate permissions for (Dev only)
64	 *
65	 * Flow:
66	 * 1. Parse and validate request parameters
67	 * 2. Handle cache clearing if requested
68	 * 3. Calculate date range for time period
69	 * 4. Check cache for existing results
70	 * 5. Connect to database and verify data availability
71	 * 6. Fetch aggregated location metrics
72	 * 7. Apply machine type filters
73	 * 8. Sort locations by money in
74	 * 9. Apply currency conversion if needed
75	 * 10. Cache and return results
76	 */
77	export async function GET(req: NextRequest) {
78	  const startTime = Date.now();
79	  const functionName = 'GET /api/locationAggregation';
80	  const user = extractUserFromRequest(req);
81	
82	  try {
83	    // ============================================================================
84	    // STEP 1: Parse and validate request parameters
85	    // ============================================================================
86	    const { searchParams } = new URL(req.url);
87	    const timePeriod = (searchParams.get('timePeriod') as TimePeriod) || '7d';
88	    const licencee = searchParams.get('licencee') || undefined;
89	    const currencyParam = searchParams.get('currency') as CurrencyCode | null;
90	    let displayCurrency: CurrencyCode = currencyParam || 'USD';
91	    const machineTypeFilter =
92	      (searchParams.get('machineTypeFilter') as LocationFilter) || null;
93	    const clearCacheParam = searchParams.get('clearCache') === 'true';
94	    const sasEvaluationOnly = searchParams.get('sasEvaluationOnly') === 'true';
95	    const basicList = searchParams.get('basicList') === 'true';
96	    const selectedLocations = searchParams.get('selectedLocations');
97	    const page = parseInt(searchParams.get('page') || '1');
98	    const requestedLimit = parseInt(searchParams.get('limit') || '50');
99	    const limit = Math.min(Math.max(requestedLimit, 1), 1000);
100	    const search = searchParams.get('search') || null;
101	    const onlineStatus =
102	      searchParams.get('onlineStatus')?.toLowerCase() || 'all';
103	
104	    // ============================================================================
105	    // STEP 2: Handle cache clearing if requested
106	    // ============================================================================
107	    if (clearCacheParam) {
108	      clearCache();
109	    }
110	
111	    // ============================================================================
112	    // STEP 3: Parse custom dates if provided (for Custom time period)
113	    // ============================================================================
114	    // NOTE: For non-Custom periods, we don't need startDate/endDate here because
115	    // the helper function getLocationsWithMetrics uses timePeriod directly to calculate
116	    // gaming day ranges per location. We only need dates for Custom periods.
117	    let customStartDate: Date | undefined;
118	    let customEndDate: Date | undefined;
119	    // For cache key generation, we still need date representation
120	    let startDate: Date | undefined;
121	    let endDate: Date | undefined;
122	
123	    if (timePeriod === 'Custom') {
124	      const customStart = searchParams.get('startDate');
125	      const customEnd = searchParams.get('endDate');
126	      if (!customStart || !customEnd) {
127	        logRouteError(
128	          functionName,
129	          'GET',
130	          '/api/locationAggregation',
131	          'Missing startDate or endDate',
132	          user
133	        );
134	        return NextResponse.json(
135	          { error: 'Missing startDate or endDate' },
136	          { status: 400 }
137	        );
138	      }
139	      // Parse dates - check if they already include time (ISO format) or just date
140	      customStartDate = customStart.includes('T')
141	        ? new Date(customStart)
142	        : new Date(customStart + 'T00:00:00.000Z');
143	      customEndDate = customEnd.includes('T')
144	        ? new Date(customEnd)
145	        : new Date(customEnd + 'T00:00:00.000Z');
146	
147	      // Validate dates are valid
148	      if (isNaN(customStartDate.getTime()) || isNaN(customEndDate.getTime())) {
149	        logRouteError(
150	          functionName,
151	          'GET',
152	          '/api/locationAggregation',
153	          `Invalid date format: startDate: ${customStart}, endDate: ${customEnd}`,
154	          user
155	        );
156	        return NextResponse.json(
157	          { error: 'Invalid date format' },
158	          { status: 400 }
159	        );
160	      }
161	
162	      startDate = customStartDate;
163	      endDate = customEndDate;
164	    } else {
165	      // For cache key: use timePeriod string representation instead of calendar dates
166	      // The actual data calculation uses gaming day ranges per location
167	      // We use undefined dates for cache key to ensure timePeriod is the primary key
168	      startDate = undefined;
169	      endDate = undefined;
170	    }
171	
172	    // ============================================================================
173	    // STEP 4: Connect to database and verify data availability
174	    // ============================================================================
175	    const db = await connectDB();
176	    if (!db) {
177	      logRouteError(
178	        functionName,
179	        'GET',
180	        '/api/locationAggregation',
181	        'Database connection failed',
182	        user
183	      );
184	      return NextResponse.json(
185	        { error: 'DB connection failed' },
186	        { status: 500 }
187	      );
188	    }
189	
190	    // Quick data availability check with timeout
191	    const dataCheckPromise = Promise.all([
192	      Meters.countDocuments({}).limit(1),
193	      GamingLocations.countDocuments({}).limit(1),
194	    ]);
195	
196	    const dataCheckTimeout = new Promise((_, reject) =>
197	      setTimeout(() => reject(new Error('Data check timeout')), 10000)
198	    );
199	
200	    try {
201	      await Promise.race([dataCheckPromise, dataCheckTimeout]);
202	    } catch (error) {
203	      console.warn(
204	        '[Location Aggregation GET API] Data availability check failed, proceeding anyway:',
205	        error
206	      );
207	    }
208	
209	    // ============================================================================
210	    // STEP 5: Get user's accessible locations (for permission filtering)
211	    // ============================================================================
212	    // DEV MODE: Allow bypassing auth for testing
213	    const isDevMode = process.env.NODE_ENV === 'development';
214	    const testUserId = searchParams.get('testUserId');
215	
216	    let userPayload;
217	    let userRoles: string[] = [];
218	    let userLocationPermissions: string[] = [];
219	    let userAccessibleLicencees: string[] | 'all' = [];
220	
221	    if (isDevMode && testUserId) {
222	      // Dev mode: Get user directly from DB for testing
223	      const UserModel = (await import('../lib/models/user')).default;
224	      const testUserResult = await UserModel.findOne({
225	        _id: testUserId,
226	      }).lean<LeanUserDocument>();
227	      if (testUserResult && !Array.isArray(testUserResult)) {
228	        const testUser = testUserResult;
229	        userRoles = (testUser.roles || []) as string[];
230	        userLocationPermissions = Array.isArray(testUser.assignedLocations)
231	          ? testUser.assignedLocations.map((id: string) => String(id))
232	          : [];
233	        userAccessibleLicencees = Array.isArray(testUser.assignedLicencees)
234	          ? testUser.assignedLicencees.map((id: string) => String(id))
235	          : [];
236	      } else {
237	        return NextResponse.json(
238	          { error: 'Test user not found' },
239	          { status: 404 }
240	        );
241	      }
242	    } else {
243	      // Normal mode: Get user from JWT
244	      userPayload = await getUserFromServer();
245	      if (!userPayload && !isDevMode) {
246	        return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });
247	      }
248	      if (userPayload) {
249	        userRoles = (userPayload.roles as string[]) || [];
250	        // Extract assignedLocations from new field only
251	        const assignedLocations = (
252	          userPayload as { assignedLocations?: string[] }
253	        )?.assignedLocations;
254	        if (Array.isArray(assignedLocations) && assignedLocations.length > 0) {
255	          userLocationPermissions = assignedLocations;
256	        }
257	      }
258	      userAccessibleLicencees = await getUserAccessibleLicenceesFromToken();
259	    }
260	
261	    // In normal mode (not dev mode or no testUserId), get licencees from token
262	    if (!isDevMode || !testUserId) {
263	      userAccessibleLicencees = await getUserAccessibleLicenceesFromToken();
264	    }
265	
266	    // ============================================================================
267	    // STEP 4.5: Determine display currency (if not provided) - AFTER DB connection
268	    // ============================================================================
269	    if (!currencyParam && userAccessibleLicencees !== 'all') {
270	      // For non-admin users, auto-detect currency from their licencee
271	      let resolvedLicencee: string | undefined =
272	        licencee && licencee !== 'all' ? licencee : undefined;
273	      if (
274	        !resolvedLicencee &&
275	        Array.isArray(userAccessibleLicencees) &&
276	        userAccessibleLicencees.length === 1
277	      ) {
278	        resolvedLicencee = userAccessibleLicencees[0];
279	      }
280	
281	      if (resolvedLicencee) {
282	        // Get licencee name from ID to properly resolve currency
283	        try {
284	          const licenceeDoc = await Licencee.findOne(
285	            { _id: resolvedLicencee },
286	            { name: 1 }
287	          ).lean<LicenceeDocument>();
288	          if (licenceeDoc && !Array.isArray(licenceeDoc) && licenceeDoc.name) {
289	            const { getLicenceeCurrency } = await import('@/lib/helpers/rates');
290	            displayCurrency = getLicenceeCurrency(licenceeDoc.name);
291	          }
292	        } catch {
293	          // Failed to get licencee name for currency - use default USD
294	        }
295	      }
296	    }
297	
298	    // Get allowed location IDs (respects user permissions and licencee filter)
299	    const allowedLocationIds = await getUserLocationFilter(
300	      userAccessibleLicencees,
301	      licencee || undefined,
302	      userLocationPermissions,
303	      userRoles
304	    );
305	
306	    // ============================================================================
307	    // STEP 6: Check cache for existing results (AFTER getting user permissions)
308	    // ============================================================================
309	    // Include user-specific permissions in cache key to prevent cross-user cache hits
310	    const cacheKey = getCacheKey({
311	      timePeriod,
312	      licencee,
313	      machineTypeFilter,
314	      startDate,
315	      endDate,
316	      page,
317	      limit,
318	      sasEvaluationOnly,
319	      basicList,
320	      selectedLocations,
321	      currency: displayCurrency,
322	      search,
323	      onlineStatus,
324	      allowedLocationIds:
325	        allowedLocationIds === 'all'
326	          ? 'all'
327	          : Array.isArray(allowedLocationIds)
328	            ? allowedLocationIds.sort().join(',')
329	            : 'none',
330	    });
331	
332	    const skipCacheForSelected = Boolean(selectedLocations);
333	
334	    if (!clearCacheParam && !skipCacheForSelected) {
335	      const cachedResult = getCachedData(cacheKey);
336	      if (cachedResult) {
337	        return NextResponse.json(cachedResult);
338	      }
339	    }
340	
341	    // ============================================================================
342	    // STEP 7: Fetch aggregated location metrics (with backend filtering)
343	    // ============================================================================
344	    const { rows, totalCount } = await getLocationsWithMetrics(
345	      licencee,
346	      page,
347	      limit,
348	      sasEvaluationOnly,
349	      basicList,
350	      selectedLocations || undefined,
351	      timePeriod,
352	      customStartDate,
353	      customEndDate,
354	      allowedLocationIds,
355	      machineTypeFilter,
356	      search,
357	      onlineStatus
358	    );
359	
360	    // Filtering is now done at database level in getLocationsWithMetrics
361	    const filteredRows = rows;
362	
363	    // ============================================================================
364	    // STEP 9: Sort locations by money in
365	    // ============================================================================
366	    const sortedRows = filteredRows.sort(
367	      (a, b) => (b.moneyIn || 0) - (a.moneyIn || 0)
368	    );
369	
370	    // ============================================================================
371	    // STEP 10: Apply currency conversion if needed
372	    // ============================================================================
373	    const currentUser = await getUserFromServer();
374	    const currentUserRoles = (currentUser?.roles as string[]) || [];
375	    const isAdminOrDev =
376	      currentUserRoles.includes('admin') ||
377	      currentUserRoles.includes('developer') ||
378	      currentUserRoles.includes('owner');
379	
380	    let convertedRows = sortedRows;
381	    if (isAdminOrDev && shouldApplyCurrencyConversion(licencee)) {
382	      convertedRows = await convertLocationCurrency(
383	        sortedRows,
384	        displayCurrency,
385	        licencee
386	      );
387	    }
388	
389	    // ============================================================================
390	    // STEP 10.5: Apply Reviewer Multiplier Scaling
391	    // ============================================================================
392	    const scaleReferenceDate = customEndDate ?? new Date();
393	    const moneyInScale = getMoneyInScale(
394	      currentUser as {
395	        moneyInMultiplier?: number | null;
396	        roles?: string[];
397	        reviewerMultiplierStartTime?: Date | string | null;
398	      },
399	      scaleReferenceDate
400	    );
401	    const moneyOutScale = getMoneyOutAndJackpotScale(
402	      currentUser as {
403	        moneyOutAndJackpotMultiplier?: number | null;
404	        roles?: string[];
405	        reviewerMultiplierStartTime?: Date | string | null;
406	      },
407	      scaleReferenceDate
408	    );
409	    if (moneyInScale !== 1 || moneyOutScale !== 1) {
410	      convertedRows = convertedRows.map(row => ({
411	        ...row,
412	        moneyIn:
413	          typeof row.moneyIn === 'number'
414	            ? row.moneyIn * moneyInScale
415	            : row.moneyIn,
416	        moneyOut:
417	          typeof row.moneyOut === 'number'
418	            ? row.moneyOut * moneyOutScale
419	            : row.moneyOut,
420	        jackpot:
421	          typeof row.jackpot === 'number'
422	            ? row.jackpot * moneyOutScale
423	            : row.jackpot,
424	        gross:
425	          typeof row.gross === 'number' ? row.gross * moneyInScale : row.gross,
426	      }));
427	    }
428	
429	    // ============================================================================
430	    // STEP 11: Cache and return results
431	    // ============================================================================
432	
433	    const result = {
434	      data: convertedRows,
435	      totalCount: totalCount,
436	      page,
437	      limit,
438	      hasMore: false,
439	      currency: displayCurrency,
440	      converted: shouldApplyCurrencyConversion(licencee),
441	    };
442	
443	    if (!clearCacheParam && !skipCacheForSelected) {
444	      setCachedData(cacheKey, result);
445	    }
446	
447	    const duration = Date.now() - startTime;
448	    logRouteFetch(
449	      functionName,
450	      'GET',
451	      '/api/locationAggregation',
452	      convertedRows.length,
453	      user,
454	      duration
455	    );
456	
457	    return NextResponse.json(result);
458	  } catch (error: unknown) {
459	    const errorMessage =
460	      error instanceof Error ? error.message : 'Internal server error';
461	
462	    logRouteError(
463	      functionName,
464	      'GET',
465	      '/api/locationAggregation',
466	      errorMessage,
467	      user
468	    );
469	
470	    // Handle specific MongoDB connection errors
471	    if (error instanceof Error) {
472	      const errorMessageLower = errorMessage.toLowerCase();
473	
474	      // MongoDB connection timeout
475	      if (
476	        errorMessageLower.includes('mongonetworktimeouterror') ||
477	        (errorMessageLower.includes('connection') &&
478	          errorMessageLower.includes('timed out'))
479	      ) {
480	        return NextResponse.json(
481	          {
482	            error: 'Database connection timeout',
483	            message:
484	              'The database is currently experiencing high load. Please try again in a few moments.',
485	            type: 'CONNECTION_TIMEOUT',
486	            retryable: true,
487	          },
488	          { status: 503 }
489	        );
490	      }
491	
492	      // MongoDB server selection error
493	      if (
494	        errorMessageLower.includes('mongoserverselectionerror') ||
495	        errorMessageLower.includes('server selection')
496	      ) {
497	        return NextResponse.json(
498	          {
499	            error: 'Database server unavailable',
500	            message:
501	              'Unable to connect to the database server. Please try again later.',
502	            type: 'SERVER_UNAVAILABLE',
503	            retryable: true,
504	          },
505	          { status: 503 }
506	        );
507	      }
508	
509	      // Generic MongoDB connection error
510	      if (
511	        errorMessageLower.includes('mongodb') ||
512	        errorMessageLower.includes('connection')
513	      ) {
514	        return NextResponse.json(
515	          {
516	            error: 'Database connection failed',
517	            message:
518	              'Unable to establish connection to the database. Please try again.',
519	            type: 'CONNECTION_ERROR',
520	            retryable: true,
521	          },
522	          { status: 503 }
523	        );
524	      }
525	    }
526	
527	    // Generic server error
528	    return NextResponse.json(
529	      {
530	        error: 'Internal server error',
531	        message: 'An unexpected error occurred while processing your request.',
532	        type: 'INTERNAL_ERROR',
533	        retryable: false,
534	      },
535	      { status: 500 }
536	    );
537	  }
538	}
